import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

const CARD_STYLES = [
  { id: 'wallet', label: 'Wallet Card', icon: '💳', desc: 'Credit card size', size: '85mm × 54mm', bg: '#0a0f1e', accent: '#ef4444', textColor: '#f1f5f9', border: '2px solid #ef4444' },
  { id: 'helmet', label: 'Helmet Sticker', icon: '🪖', desc: 'Square', size: '60mm × 60mm', bg: '#111827', accent: '#f59e0b', textColor: '#f1f5f9', border: '2px solid #f59e0b' },
  { id: 'car', label: 'Car', icon: '🚗', desc: 'Wide', size: '120mm × 60mm', bg: '#1a1a2e', accent: '#3b82f6', textColor: '#f1f5f9', border: '2px solid #3b82f6' },
  { id: 'badge', label: 'Badge', icon: '🪪', desc: 'Portrait', size: '54mm × 85mm', bg: '#0f172a', accent: '#10b981', textColor: '#f1f5f9', border: '2px solid #10b981' },
];

function Toast({ msg, type, onClose }) {
  useEffect(() => {
    const t = setTimeout(onClose, 3000);
    return () => clearTimeout(t);
  }, [onClose]);
  return <div className={`toast toast-${type}`}>{msg}</div>;
}

export default function QRPage() {
  const { API } = useAuth();
  const [qr, setQr] = useState(null);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState('wallet');
  const [toast, setToast] = useState(null);
  const printRef = useRef();

  const showToast = (msg, type = 'success') => setToast({ msg, type });

  useEffect(() => {
    const token = localStorage.getItem("lifeqr_token"); // ✅ FIXED

    Promise.all([
      axios.get(`${API}/qr/active`, {
        headers: { Authorization: `Bearer ${token}` }
      }),
      axios.get(`${API}/profile`, {
        headers: { Authorization: `Bearer ${token}` }
      })
    ])
    .then(([qRes, pRes]) => {
      setQr(qRes.data.qr);
      setProfile(pRes.data.profile);
    })
    .catch(err => console.error(err))
    .finally(() => setLoading(false));

  }, [API]);

  const generateQR = async () => {
    setGenerating(true);
    const token = localStorage.getItem("lifeqr_token"); // ✅ FIXED

    try {
      const res = await axios.post(`${API}/qr/generate`, {}, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setQr(res.data);
      showToast('QR generated!');
    } catch (err) {
      console.error(err);
      showToast('Failed to generate QR', 'error');
    } finally {
      setGenerating(false);
    }
  };

  const handlePrint = () => {
    const printWindow = window.open('', '_blank');
    printWindow.document.write(`
      <html>
      <body style="text-align:center">
        <h2>LifeQR</h2>
        <img src="${qr?.qrDataUrl}" />
      </body>
      </html>
    `);
    printWindow.document.close();
  };

  if (loading) return <h2 style={{ textAlign: "center" }}>Loading...</h2>;

  return (
    <div style={{ padding: 20 }}>
      {toast && <Toast msg={toast.msg} type={toast.type} onClose={() => setToast(null)} />}

      <h1>My QR Code</h1>

      {!qr ? (
        <button onClick={generateQR} disabled={generating}>
          {generating ? "Generating..." : "Generate QR"}
        </button>
      ) : (
        <div>
          <img src={qr.qrDataUrl} alt="QR" width={200} />
          <p>Expires: {new Date(qr.expiresAt).toLocaleDateString()}</p>
          <button onClick={generateQR}>Regenerate QR</button>
          <button onClick={handlePrint}>Print QR</button>
        </div>
      )}
    </div>
  );
}
